// =============================================================
// UTILIDADES
// =============================================================

function haversine(lat1, lon1, lat2, lon2) {
  const R = 6371000;
  const phi1 = lat1 * Math.PI / 180, phi2 = lat2 * Math.PI / 180;
  const dphi = (lat2 - lat1) * Math.PI / 180;
  const dlambda = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dphi/2)**2 + Math.cos(phi1) * Math.cos(phi2) * Math.sin(dlambda/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

function checkProximity(userLat, userLng) {
  const alerts = [];
  for (const s of SENDEROS) {
    const dInicio = haversine(userLat, userLng, s.geofence.inicio.lat, s.geofence.inicio.lng);
    const dFin   = haversine(userLat, userLng, s.geofence.fin.lat,    s.geofence.fin.lng);
    if (dInicio <= s.geofence.inicio.radio) alerts.push({ sendero: s, tipo: 'inicio', distancia: Math.round(dInicio) });
    if (dFin    <= s.geofence.fin.radio)    alerts.push({ sendero: s, tipo: 'fin',    distancia: Math.round(dFin) });
  }
  return alerts;
}

function getSenderoById(id) { return SENDEROS.find(s => s.id === id) || null; }
function getSenderosByActividad(act) { return SENDEROS.filter(s => s.actividades.includes(act)); }

// Retorna coords de un sendero truncadas en un índice específico
function getCoordsHastaIdx(senderoId, idx) {
  const s = getSenderoById(senderoId);
  if (!s) return [];
  return s.coords.slice(0, idx + 1);
}

// Construye el GeoJSON de segmentos para una ruta completa
function buildRutaGeoJSON(rutaId) {
  const ruta = RUTAS[rutaId];
  if (!ruta) return null;
  const features = [];
  ruta.pasos.forEach((paso, i) => {
    let coords = [];
    if (paso.tipo === 'ripio') {
      coords = RIPIO_ACCESO;
    } else if (paso.tipo === 'sendero') {
      const s = getSenderoById(paso.id);
      if (s) coords = s.coords;
    } else if (paso.tipo === 'acceso') {
      coords = getCoordsHastaIdx(paso.id, paso.hasta_idx);
    }
    if (coords.length > 1) {
      features.push({
        type: 'Feature',
        properties: { label: paso.label, color: paso.color, paso: i },
        geometry: { type: 'LineString', coordinates: coords }
      });
    }
  });
  return { type: 'FeatureCollection', features };
}
